// A simple functional component
function Greeting() {
  return <h1>Hello, World!</h1>;
}

// You can also use arrow functions:
const Welcome = () => {
  return <h1>Welcome to React!</h1>;
};

// Both are valid functional components!

## Rules for Functional Components

### 1. Must Return JSX
Every component must return JSX (or null):

```javascript
function ValidComponent() {
  return <div>Valid!</div>;
}

function InvalidComponent() {
  console.log("No return!"); // ❌ Returns undefined!
}
```

### 2. Single Parent Element
JSX must have a single root element:

```javascript
// ❌ Multiple roots - won't work!
function Broken() {
  return (
    <h1>Title</h1>
    <p>Content</p>
  );
}

// ✅ Wrap in a parent div
function Fixed() {
  return (
    <div>
      <h1>Title</h1>
      <p>Content</p>
    </div>
  );
}
```

### 3. Close All Tags
All JSX tags must be closed:

```javascript
// ❌ Missing closing tag
<img src="photo.jpg">

// ✅ Self-closing
<img src="photo.jpg" />
```

// Button component
function MyButton() {
  return <button>Click me!</button>;
}

// Card component
function ProfileCard() {
  return (
    <div className="card">
      <h2>User Name</h2>
      <p>Developer & Designer</p>
    </div>
  );
}

// Navigation component
function NavBar() {
  return (
    <nav>
      <a href="/home">Home</a>
      <a href="/about">About</a>
      <a href="/contact">Contact</a>
    </nav>
  );
}

Once you define a component, you can use it **multiple times**:

```javascript
function Greeting() {
  return <h1>Hello!</h1>;
}

// Use it wherever you need!
function App() {
  return (
    <div>
      <Greeting />
      <Greeting />
      <Greeting />
    </div>
  );
}
```

This is much better than copying and pasting HTML!

